import React, { useState, useEffect } from 'react';
import {
  Box,
  Typography,
  TextField,
  Button,
  Paper,
  Divider,
  Container,
  InputAdornment,
  IconButton,
  Tooltip,
  Alert,
  Snackbar
} from '@mui/material';
import {
  Save,
  Image,
  ColorLens,
  Visibility,
  Email,
  Phone,
  Title
} from '@mui/icons-material';
import { useFirebase } from '../../context/FirebaseContext';
import { AppSettings } from '../../types';

const initialSettings: Partial<AppSettings> = {
  appName: '',
  logoUrl: '',
  heroImageUrl: '',
  primaryColor: '#1976D2',
  secondaryColor: '#2196F3',
  contactEmail: '',
  contactPhone: ''
};

const AppSettingsForm: React.FC = () => {
  const { appSettings, updateSettings } = useFirebase();
  const [settings, setSettings] = useState<Partial<AppSettings>>(initialSettings);
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Загрузка настроек при монтировании компонента
  useEffect(() => {
    if (appSettings) {
      setSettings({
        appName: appSettings.appName || '',
        logoUrl: appSettings.logoUrl || '',
        heroImageUrl: appSettings.heroImageUrl || '',
        primaryColor: appSettings.primaryColor || '#1976D2',
        secondaryColor: appSettings.secondaryColor || '#2196F3',
        contactEmail: appSettings.contactEmail || '',
        contactPhone: appSettings.contactPhone || ''
      });
    }
  }, [appSettings]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setSettings(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSave = async () => {
    try {
      setLoading(true);
      setError(null);
      
      const result = await updateSettings(settings);
      
      if (result) {
        setSuccess(true);
      } else {
        setError('Произошла ошибка при сохранении настроек');
      }
    } catch (err) {
      console.error('Ошибка при сохранении настроек:', err);
      setError('Произошла ошибка при сохранении настроек');
    } finally {
      setLoading(false);
    }
  };

  const handleCloseSnackbar = () => {
    setSuccess(false);
  };

  const previewImage = (url: string) => {
    if (!url) return;
    window.open(url, '_blank');
  };

  return (
    <Paper sx={{ p: 3, borderRadius: 2, mb: 4 }}>
      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2 }}>
        <Typography variant="h5" component="h2">
          Настройки приложения
        </Typography>
        <Button
          variant="contained"
          color="primary"
          startIcon={<Save />}
          onClick={handleSave}
          disabled={loading}
        >
          Сохранить
        </Button>
      </Box>
      
      <Divider sx={{ mb: 3 }} />
      
      <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 3 }}>
        {/* Основные настройки */}
        <Box sx={{ flex: '1 1 350px', minWidth: '300px' }}>
          <Typography variant="h6" gutterBottom>
            Основные настройки
          </Typography>
          
          <TextField
            fullWidth
            label="Название приложения"
            name="appName"
            value={settings.appName}
            onChange={handleChange}
            margin="normal"
            InputProps={{
              startAdornment: (
                <InputAdornment position="start">
                  <Title />
                </InputAdornment>
              )
            }}
          />
          
          <TextField
            fullWidth
            label="URL логотипа"
            name="logoUrl"
            value={settings.logoUrl}
            onChange={handleChange}
            margin="normal"
            helperText="URL изображения логотипа, которое будет отображаться в шапке"
            InputProps={{
              startAdornment: (
                <InputAdornment position="start">
                  <Image />
                </InputAdornment>
              ),
              endAdornment: (
                <InputAdornment position="end">
                  <Tooltip title="Просмотреть изображение">
                    <IconButton 
                      edge="end" 
                      onClick={() => previewImage(settings.logoUrl || '')}
                      disabled={!settings.logoUrl}
                    >
                      <Visibility />
                    </IconButton>
                  </Tooltip>
                </InputAdornment>
              )
            }}
          />
          
          <TextField
            fullWidth
            label="URL изображения героя"
            name="heroImageUrl"
            value={settings.heroImageUrl}
            onChange={handleChange}
            margin="normal"
            helperText="URL изображения для главного баннера на домашней странице"
            InputProps={{
              startAdornment: (
                <InputAdornment position="start">
                  <Image />
                </InputAdornment>
              ),
              endAdornment: (
                <InputAdornment position="end">
                  <Tooltip title="Просмотреть изображение">
                    <IconButton 
                      edge="end" 
                      onClick={() => previewImage(settings.heroImageUrl || '')}
                      disabled={!settings.heroImageUrl}
                    >
                      <Visibility />
                    </IconButton>
                  </Tooltip>
                </InputAdornment>
              )
            }}
          />
        </Box>
        
        {/* Цвета и контакты */}
        <Box sx={{ flex: '1 1 350px', minWidth: '300px' }}>
          <Typography variant="h6" gutterBottom>
            Цвета и контакты
          </Typography>
          
          <TextField
            fullWidth
            label="Основной цвет"
            name="primaryColor"
            value={settings.primaryColor}
            onChange={handleChange}
            margin="normal"
            type="color"
            InputProps={{
              startAdornment: (
                <InputAdornment position="start">
                  <ColorLens />
                </InputAdornment>
              )
            }}
          />
          
          <TextField
            fullWidth
            label="Вторичный цвет"
            name="secondaryColor"
            value={settings.secondaryColor}
            onChange={handleChange}
            margin="normal"
            type="color"
            InputProps={{
              startAdornment: (
                <InputAdornment position="start">
                  <ColorLens />
                </InputAdornment>
              )
            }}
          />
          
          <TextField
            fullWidth
            label="Контактный Email"
            name="contactEmail"
            value={settings.contactEmail}
            onChange={handleChange}
            margin="normal"
            type="email"
            InputProps={{
              startAdornment: (
                <InputAdornment position="start">
                  <Email />
                </InputAdornment>
              )
            }}
          />
          
          <TextField
            fullWidth
            label="Контактный телефон"
            name="contactPhone"
            value={settings.contactPhone}
            onChange={handleChange}
            margin="normal"
            InputProps={{
              startAdornment: (
                <InputAdornment position="start">
                  <Phone />
                </InputAdornment>
              )
            }}
          />
        </Box>
      </Box>
      
      {error && (
        <Alert severity="error" sx={{ mt: 3 }}>
          {error}
        </Alert>
      )}
      
      <Snackbar
        open={success}
        autoHideDuration={5000}
        onClose={handleCloseSnackbar}
        message="Настройки успешно сохранены"
      />
    </Paper>
  );
};

export default AppSettingsForm;
